"use strict";(globalThis.webpackChunkinfoseclessons=globalThis.webpackChunkinfoseclessons||[]).push([[8046],{30004(e,n,t){t.r(n),t.d(n,{assets:()=>d,contentTitle:()=>o,default:()=>h,frontMatter:()=>a,metadata:()=>r,toc:()=>l});const r=JSON.parse('{"id":"general-security/mobile-and-iot/embedded-and-iot-security","title":"Embedded Systems, IoT, and ICS Security","description":"Securing embedded systems, IoT devices, and industrial control systems \u2014 from Raspberry Pi and FPGAs to SCADA networks, smart meters, and design constraints.","source":"@site/docs/general-security/mobile-and-iot/embedded-and-iot-security.md","sourceDirName":"general-security/mobile-and-iot","slug":"/general-security/embedded-and-iot-security","permalink":"/infoseclessons/general-security/embedded-and-iot-security","draft":false,"unlisted":false,"editUrl":"https://github.com/farzaliyevemil/infoseclessons/edit/main/docs/general-security/mobile-and-iot/embedded-and-iot-security.md","tags":[],"version":"current","sidebarPosition":11,"frontMatter":{"id":"embedded-and-iot-security","title":"Embedded Systems, IoT, and ICS Security","description":"Securing embedded systems, IoT devices, and industrial control systems \u2014 from Raspberry Pi and FPGAs to SCADA networks, smart meters, and design constraints.","slug":"/general-security/embedded-and-iot-security","sidebar_position":11,"status":"reference","last_reviewed":"2026-04-23T00:00:00.000Z","keywords":["embedded systems","IoT","SCADA","ICS","Raspberry Pi","FPGA","smart devices","RTOS"],"difficulty":"intermediate"},"sidebar":"tutorialSidebar","previous":{"title":"\ud83d\udcf1 Mobile, IoT & Physical","permalink":"/infoseclessons/category/-mobile-iot--physical"},"next":{"title":"Physical Security Controls","permalink":"/infoseclessons/general-security/physical-security"}}');var s=t(74848),i=t(28453);const a={id:"embedded-and-iot-security",title:"Embedded Systems, IoT, and ICS Security",description:"Securing embedded systems, IoT devices, and industrial control systems \u2014 from Raspberry Pi and FPGAs to SCADA networks, smart meters, and design constraints.",slug:"/general-security/embedded-and-iot-security",sidebar_position:11,status:"reference",last_reviewed:new Date("2026-04-23T00:00:00.000Z"),keywords:["embedded systems","IoT","SCADA","ICS","Raspberry Pi","FPGA","smart devices","RTOS"],difficulty:"intermediate"},o="Embedded Systems, IoT, and ICS Security",d={},l=[{value:"Why this matters",id:"why-this-matters",level:2},{value:"Core concepts",id:"core-concepts",level:2},{value:"Embedded vs general-purpose",id:"embedded-vs-general-purpose",level:3},{value:"Development boards \u2014 Raspberry Pi, Arduino, FPGA",id:"development-boards--raspberry-pi-arduino-fpga",level:3},{value:"SCADA / ICS overview",id:"scada--ics-overview",level:3},{value:"IoT device anatomy",id:"iot-device-anatomy",level:3},{value:"Specialised systems \u2014 medical, vehicle, aircraft, smart meters",id:"specialised-systems--medical-vehicle-aircraft-smart-meters",level:3},{value:"Communication technologies \u2014 5G, narrow-band, baseband, SIM, Zigbee",id:"communication-technologies--5g-narrow-band-baseband-sim-zigbee",level:3},{value:"Design constraints \u2014 power, compute, patching, implied trust",id:"design-constraints--power-compute-patching-implied-trust",level:3},{value:"Architecture diagram",id:"architecture-diagram",level:2},{value:"Hands-on / practice",id:"hands-on--practice",level:2},{value:"1. Fingerprint an IoT device on the network",id:"1-fingerprint-an-iot-device-on-the-network",level:3},{value:"2. Check default credentials against a vendor list",id:"2-check-default-credentials-against-a-vendor-list",level:3},{value:"3. OT / IT segmentation review",id:"3-ot--it-segmentation-review",level:3},{value:"4. Firmware version audit",id:"4-firmware-version-audit",level:3},{value:"5. Baseline network traffic from an IoT device",id:"5-baseline-network-traffic-from-an-iot-device",level:3},{value:"Worked example",id:"worked-example",level:2},{value:"Troubleshooting and pitfalls",id:"troubleshooting-and-pitfalls",level:2},{value:"Key takeaways",id:"key-takeaways",level:2},{value:"References",id:"references",level:2}];function c(e){const n={a:"a",code:"code",em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",li:"li",mermaid:"mermaid",p:"p",pre:"pre",strong:"strong",table:"table",tbody:"tbody",td:"td",th:"th",thead:"thead",tr:"tr",ul:"ul",...(0,i.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(n.header,{children:(0,s.jsx)(n.h1,{id:"embedded-systems-iot-and-ics-security",children:"Embedded Systems, IoT, and ICS Security"})}),"\n",(0,s.jsx)(n.h2,{id:"why-this-matters",children:"Why this matters"}),"\n",(0,s.jsx)(n.p,{children:"An enterprise network used to be a list of servers, laptops, and printers. The same network today also runs the badge readers at the door, the HVAC controller in the basement, the IP cameras in the parking lot, the label printer on the shop floor, the PLC driving the conveyor, the infusion pump on a patient floor, and the smart TV in the boardroom. Most of those devices were bought by a team that does not report to IT, installed by an integrator who left years ago, and patched \u2014 if ever \u2014 only when the vendor says so. A typical mid-sized enterprise in 2026 has more embedded devices than laptops on its network, and only a fraction of them appear in the CMDB."}),"\n",(0,s.jsxs)(n.p,{children:["Each one of those devices is an ",(0,s.jsx)(n.strong,{children:"embedded system"}),": a purpose-built computer hidden inside something that is not sold as a computer. When they talk to each other across IP we call the assembly ",(0,s.jsx)(n.strong,{children:"IoT"})," (Internet of Things). When they control physical processes \u2014 pumps, valves, turbines, conveyor belts \u2014 we call it ",(0,s.jsx)(n.strong,{children:"OT"})," (Operational Technology), and the umbrella name for the control software is ",(0,s.jsx)(n.strong,{children:"ICS"})," (Industrial Control Systems) or ",(0,s.jsx)(n.strong,{children:"SCADA"})," (Supervisory Control and Data Acquisition). These categories overlap; a smart thermostat is IoT, the building-wide HVAC controller it talks to is OT, and the historian that stores all of that for reporting sits astride both worlds."]}),"\n",(0,s.jsx)(n.p,{children:'The security story is ugly. Embedded vendors optimise for cost and feature velocity, not security. Default credentials are documented in the manual. Firmware updates ship late, through a USB port, maybe never. The device runs a 2014 Linux kernel on a chip that has not been revved since manufacturing. The network stack trusts anything on the same VLAN. And because the device is "not a computer", nobody asks whether it should be on the domain, be scanned, be logged, or have MFA.'}),"\n",(0,s.jsx)(n.p,{children:"The incidents track the neglect. Mirai took over hundreds of thousands of IP cameras and DVRs using a list of 62 default credentials. Stuxnet showed a nation-state could wreck industrial centrifuges via a PLC. The Target breach started with an HVAC vendor. Ransomware on a single HMI workstation has halted pipelines, hospitals, and food-processing plants. None of these required novel cryptographic breakthroughs; they all required the defender to leave an embedded device with the vendor defaults on a reachable network."}),"\n",(0,s.jsx)(n.p,{children:"The economics of the defender's side are equally awkward. A SIEM licence gets budget because the CFO can picture a breach. Segmenting the building-automation VLAN, adding a jump host for the integrator, and forbidding the HVAC vendor's laptop from direct network access \u2014 those do not show up on anyone's dashboard until the day they prevent an incident that now never happens. The work is unglamorous, cross-functional, and easy to defer. It is also consistently the highest-leverage thing a small security team can do."}),"\n",(0,s.jsxs)(n.p,{children:["This lesson walks the landscape: what the hardware categories are (Raspberry Pi, Arduino, FPGA, SoC), how SCADA/ICS environments differ from IT networks, what specialised systems (medical, vehicle, aircraft, smart meters) bring with them, which communication technologies (5G, Zigbee, narrow-band, SIM) show up in these devices, and what design constraints \u2014 power, compute, patching, implied trust \u2014 shape every decision. We end with a worked example at ",(0,s.jsx)(n.code,{children:"example.local"}),": a mid-sized enterprise deploying an industrial SCADA stack for facility HVAC, and how security gets threaded into each layer."]}),"\n",(0,s.jsx)(n.h2,{id:"core-concepts",children:"Core concepts"}),"\n",(0,s.jsx)(n.h3,{id:"embedded-vs-general-purpose",children:"Embedded vs general-purpose"}),"\n",(0,s.jsxs)(n.p,{children:["A ",(0,s.jsx)(n.strong,{children:"general-purpose computer"})," \u2014 your laptop, a server, a VM \u2014 is built to run arbitrary workloads. It has a full OS, a package manager, a patching story, a user model, and an update lifecycle measured in days. An ",(0,s.jsx)(n.strong,{children:"embedded system"})," is the opposite: a fixed-purpose computer soldered into a larger product, built to do one job for ten years. It may run Linux, an RTOS, or no OS at all. It often has no package manager, no remote shell, no syslog, and no user accounts beyond a root prompt on a serial port nobody has ever plugged into."]}),"\n",(0,s.jsx)(n.p,{children:"The consequences for security:"}),"\n",(0,s.jsxs)(n.table,{children:[(0,s.jsx)(n.thead,{children:(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.th,{children:"Property"}),(0,s.jsx)(n.th,{children:"General-purpose"}),(0,s.jsx)(n.th,{children:"Embedded"})]})}),(0,s.jsxs)(n.tbody,{children:[(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:"Patching cadence"}),(0,s.jsx)(n.td,{children:"Monthly at minimum"}),(0,s.jsx)(n.td,{children:"Rare, often never"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:"Update channel"}),(0,s.jsx)(n.td,{children:"OS vendor + app store"}),(0,s.jsx)(n.td,{children:"Firmware image from manufacturer"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:"User model"}),(0,s.jsx)(n.td,{children:"Multi-user, RBAC"}),(0,s.jsx)(n.td,{children:"Usually none, or one hard-coded admin"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:"Attack surface"}),(0,s.jsx)(n.td,{children:"Wide but known"}),(0,s.jsx)(n.td,{children:"Narrow but unmonitored"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:"Lifecycle"}),(0,s.jsx)(n.td,{children:"3\u20135 years"}),(0,s.jsx)(n.td,{children:"10\u201320 years in the field"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:"Monitoring"}),(0,s.jsx)(n.td,{children:"SIEM agents, EDR"}),(0,s.jsx)(n.td,{children:"Usually none"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:"Development priorities"}),(0,s.jsx)(n.td,{children:"Security + compatibility"}),(0,s.jsx)(n.td,{children:"Cost + feature velocity"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:"Regulation"}),(0,s.jsx)(n.td,{children:"Sector specific"}),(0,s.jsx)(n.td,{children:"Often none at all"})]})]})]}),"\n",(0,s.jsxs)(n.p,{children:["The payoff is predictability: an embedded system does exactly one thing, forever, reliably. The price is that when a vulnerability lands, you have limited tools to respond. The vast majority of embedded security incidents come from devices doing ",(0,s.jsx)(n.strong,{children:"exactly what they were designed to do"})," \u2014 responding to a Modbus write, accepting a firmware image, trusting an unauthenticated peer \u2014 being used by an attacker the designer never contemplated."]}),"\n",(0,s.jsx)(n.h3,{id:"development-boards--raspberry-pi-arduino-fpga",children:"Development boards \u2014 Raspberry Pi, Arduino, FPGA"}),"\n",(0,s.jsx)(n.p,{children:"Three prototyping platforms that keep showing up in enterprise environments \u2014 sometimes as legitimate tools, sometimes as shadow IT someone wired into a production network."}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Raspberry Pi."})," A low-cost single-board computer (under 100 USD) running a full Linux distribution on an ARM processor. Typical specs include a quad-core CPU, several gigabytes of RAM, Wi-Fi on 2.4 and 5 GHz, Bluetooth, Gigabit Ethernet, USB, GPIO pins for hardware interfacing, and enough horsepower to act as a desktop. Because it is a full Linux box, treat it like any other Linux host: unique credentials, SSH key auth, automatic updates, host firewall, and inclusion in your asset inventory. The convenience that made it popular with hobbyists also makes it popular as an unsanctioned jump box plugged under someone's desk, and as a production element in low-volume commercial products."]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Arduino."})," A microcontroller board, not a computer. No OS, no filesystem, no network by default \u2014 the program runs directly on the chip when power is applied. Designed for sensor input and actuator output, specifically for interfacing with sensors and devices. If power is lost, once it is restored the device can begin functioning again \u2014 unlike a computer, which would have to reboot. The Arduino platform is expanded via a series of add-on boards called ",(0,s.jsx)(n.strong,{children:"shields"})," that layer in networking, displays, data logging, and other specific functions. The security story is different from a Pi: there is rarely a network interface to attack, but the code on the chip is usually unsigned, and replacing it physically is trivial. Arduinos show up inside custom hardware projects, lab equipment, and maker-built facility add-ons."]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"FPGA (Field Programmable Gate Array)."})," Semiconductor chips built from a matrix of configurable logic blocks (CLBs) connected via programmable interconnects. The logic is programmed after manufacturing via hardware description languages like VHDL or Verilog, and can be reprogrammed as the design evolves. Unlike ASICs (which are etched for a single function at the factory) an FPGA can be reconfigured in the field. Used for digital signal processing, image and video pipelines, cryptographic acceleration, and software-defined radios where the radio's function is defined in software and can be updated. Security properties: the bitstream loaded into the FPGA can be signed or encrypted; older or cheap parts do not enforce this and a malicious bitstream can be swapped in. FPGAs excel at parallelism \u2014 they can process many independent tasks at once, which is why they turn up in real-time image pipelines and crypto accelerators. Disadvantages: they require HDL skills to program, and for the same workload they can consume more power than a custom ASIC."]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Wearables."})," A close cousin of the development board world \u2014 fitness trackers, smartwatches, biometric sensors built around a tiny computer usually running a stripped-down Linux or an RTOS. Wearables are increasingly rich data sources (heart rate, sleep, location, activity), and protecting that data is the central security objective."]}),"\n",(0,s.jsx)(n.h3,{id:"scada--ics-overview",children:"SCADA / ICS overview"}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"SCADA"})," (Supervisory Control and Data Acquisition) is the umbrella term for systems that control physical processes via networked computers. Depending on the industry you may also hear ",(0,s.jsx)(n.strong,{children:"DCS"})," (Distributed Control System) or ",(0,s.jsx)(n.strong,{children:"ICS"})," (Industrial Control Systems) \u2014 for practical purposes they describe the same thing. Wherever computers directly control a physical process, SCADA is in the picture."]}),"\n",(0,s.jsx)(n.p,{children:"SCADA shows up in many industries:"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Facilities."})," Building automation, HVAC, elevators, water pressure pumps, fire alarms, access controls."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Industrial plants."})," Environmental monitoring, surveillance, fire systems, general process computer control."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Manufacturing."})," Programmable logic controllers executing process-specific instructions based on sensor readings and actuator settings \u2014 strict network segmentation is the standard practice here because manufacturing lines are business-critical."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Energy."})," Electrical generation and distribution, chemical, petroleum, pipelines, nuclear, solar, hydrothermal. Distribution in particular spans geography \u2014 pipelines and transmission lines sit outside the corporate perimeter."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Logistics."})," Moving material from point A to point B by sea, rail, road, or air. Two things under control: the transport system and the material itself."]}),"\n"]}),"\n",(0,s.jsxs)(n.p,{children:["A typical SCADA stack has five recognisable layers, usually mapped to the ",(0,s.jsx)(n.strong,{children:"Purdue Enterprise Reference Architecture"})," levels:"]}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Level 0 \u2014 Field devices."})," Sensors and actuators \u2014 temperature probes, flow meters, valves, motors."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Level 1 \u2014 Controllers."})," PLCs (Programmable Logic Controllers) and RTUs (Remote Terminal Units) that read sensors and drive actuators in real time."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Level 2 \u2014 Supervisory / HMI."})," Human-Machine Interface workstations where operators see the process and can intervene. Historians (time-series databases) record everything."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Level 3 \u2014 Operations management."})," Plant-wide MES, batch managers, engineering workstations."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Levels 4 / 5 \u2014 Enterprise IT."})," Corporate network, ERP, email, the rest of the business."]}),"\n"]}),"\n",(0,s.jsxs)(n.p,{children:["Historically Levels 0\u20133 were ",(0,s.jsx)(n.strong,{children:"air-gapped"})," from the IT network \u2014 no direct network connection, data moved by USB or manual entry. That isolation is eroding: modern business wants real-time production data in the ERP, remote vendor support, and cloud analytics. Each new connection expands the attack surface, and every SCADA environment now needs the IT-style controls that used to be unnecessary: segmentation, monitoring, authentication, patching. The closer the SCADA network looks to a regular IT network, the more IT-style security it needs."]}),"\n",(0,s.jsx)(n.h3,{id:"iot-device-anatomy",children:"IoT device anatomy"}),"\n",(0,s.jsx)(n.p,{children:"Despite the variety, most IoT devices share a common shape:"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"A sensor or actuator"})," \u2014 the reason the device exists (temperature probe, camera sensor, motor driver)."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"A microcontroller or SoC"})," \u2014 runs the firmware, talks to the sensor, drives the radio."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"A radio"})," \u2014 Wi-Fi, Bluetooth, Zigbee, cellular, LoRa, or similar."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"A firmware image"})," \u2014 usually an embedded Linux or RTOS built once and deployed to millions of units."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"A cloud backend"})," \u2014 the vendor's service the device phones home to, often via MQTT or HTTPS."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"A mobile app"})," \u2014 how the end user configures the device."]}),"\n"]}),"\n",(0,s.jsx)(n.p,{children:"The common failure modes track those parts: default credentials, unsigned firmware, plaintext protocols, hard-coded cloud endpoints, and cloud APIs that trust any authenticated device. IoT vendors chase feature scale; security comes second if at all."}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Sensors"})," deserve a sentence of their own. They translate a physical signal (temperature, pressure, voltage, position, humidity) into a digital reading. Precision, range, sample rate, and environmental resilience are the design axes. A humidity sensor that drifts by 5% once a year still functions; a sensor feeding a safety interlock that drifts silently can cause an incident. For security purposes, sensors are mostly interesting because their ",(0,s.jsx)(n.strong,{children:"readings are inputs"})," that downstream logic trusts \u2014 spoofing a sensor is sometimes easier than breaking the controller."]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Facility automation"})," is where all of this comes together in a building: security systems, HVAC, fire sensors, elevator controls, door readers, and IFTTT-style automation rules that tie events across them. The payoff is speed of response and removed manual errors; the cost is a dense, interconnected control plane that expands the blast radius of a single compromise."]}),"\n",(0,s.jsx)(n.h3,{id:"specialised-systems--medical-vehicle-aircraft-smart-meters",children:"Specialised systems \u2014 medical, vehicle, aircraft, smart meters"}),"\n",(0,s.jsx)(n.p,{children:"Four specialised categories that deserve individual treatment because exploitation has safety consequences \u2014 people get hurt, not just data lost."}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Medical devices."})," Pacemakers, infusion pumps, MRI machines, lab analysers. Often run stripped-down embedded Linux kernels that were current when the device shipped five or ten years ago. Regulatory approval (FDA 510(k), EU MDR) makes patching a slow process because any change may require recertification. As the base kernel version ages, new vulnerabilities land in the upstream code and the embedded device stays frozen on an unpatchable version. Patient safety makes them high-impact targets, which is why the FDA now explicitly requires cybersecurity in pre-market submissions."]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Vehicles."})," A modern car has hundreds of microcontrollers on a ",(0,s.jsx)(n.strong,{children:"CAN bus"})," (Controller Area Network). Robert Bosch developed the CAN bus in the 1980s to replace massive wiring harnesses, and when BMW shipped the first CAN car in 1986 the harness weight dropped by over 100 pounds. Since 2008 a CAN bus is mandatory on new US and European cars. The bus was designed without authentication \u2014 any node can send any message \u2014 and research (Miller and Valasek's 2015 Jeep hack, ongoing Tesla and Toyota CAN work) has repeatedly shown full remote control is feasible when infotainment and drivetrain share a bus. Demonstrated attacks include disabling a moving vehicle over the internet and manipulating entertainment, steering, and braking."]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Aircraft."}),' Modern cockpits are "all-glass" \u2014 touchscreens replacing analog gauges. In-flight entertainment often runs standard Linux and sits on the same airframe network as flight control, separated by firewalls rather than physical isolation. Patching is strangled by aviation regulation; vulnerabilities pile up on legacy OS versions while the same bugs get cleaned up everywhere else.']}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Smart meters."})," Advanced Metering Infrastructure (AMI) is a US Department of Energy initiative that gives utilities two-way communication with every meter \u2014 real-time usage (granularity in minutes, not a monthly manual read), remote service change, disconnect, reconnect, outage detection. Attack surface covers the meter's radio, the neighbourhood concentrator, and the utility head-end. A compromised head-end can issue mass disconnect commands \u2014 the impact of that is not theoretical."]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Real-time operating systems (RTOSs)."})," Many of these specialised devices run an RTOS rather than a general-purpose OS. An RTOS is designed so each input is processed within a defined time budget; general-purpose OSes like Windows and Linux make poor real-time processors because the overhead of scheduling multiple threads introduces unpredictable latency. The security consequence of RTOS design is that any event which interferes with the timing budget can cause the system to fail its task \u2014 and because an RTOS is tightly scoped to one job, patches and updates are rare. Plan on long-lived, unpatched, timing-sensitive devices and build compensating controls accordingly."]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Surveillance systems"})," also deserve their own paragraph. High-end digital cameras with image processors and 4K feeds show up in media and enterprise environments, and most carry always-on VPNs because the footage is valuable enough to warrant it. At the other end of the spectrum are cheap consumer cameras \u2014 home surveillance, baby monitors, doorbells \u2014 that ship with weak defaults and live a second life as Mirai botnet nodes."]}),"\n",(0,s.jsx)(n.p,{children:"Other specialised systems worth naming:"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"VoIP phones."})," The enterprise voice network is IP traffic now. VoIP is vulnerable to denial of service, toll fraud (outsiders making international calls on your PBX), eavesdropping, and spoofing. Traditional telco used to manage most of this; with VoIP it is on you. SIP over TLS and SRTP for the media stream are the baseline."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"HVAC / building automation."}),' Not glamorous but consequential \u2014 the 2013 Target breach entry point was an HVAC vendor. "Smart building" systems have moved from stand-alone to internet-connected for central monitoring; the attack surface has grown accordingly.']}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Drones / UAVs."})," Remote radio control, camera telemetry, autopilot firmware. Even hobbyist drones carry sophisticated autopilots. Enterprise deployments (inspection, surveying, delivery) add fleet management and video ingestion."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Multifunction printers / MFPs."})," Print server + scan + fax, often running a full Linux with no one patching it. Research has demonstrated MFPs passing malware to the workstations printing through them."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Surveillance cameras."})," Often shipped with hard-coded credentials \u2014 the Mirai botnet family lives on these. Modern high-end cameras are a small computer with a network stack, image processor, and 4K video output; many offer always-on VPN for live feeds."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"RTOS-driven industrial equipment."})," Robots, anti-lock braking computers, assembly-line controllers \u2014 anywhere hard real-time response is required. Patches are rare because the device is not a general-purpose platform."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"System-on-a-Chip (SoC) designs."})," A complete compute platform (CPU, GPU, networking, sometimes memory) on one die. Powers phones, tablets, embedded devices. Security properties are inherited from the SoC vendor \u2014 baseband isolation, secure boot, trusted execution environment \u2014 and are often opaque to the device integrator."]}),"\n"]}),"\n",(0,s.jsx)(n.h3,{id:"communication-technologies--5g-narrow-band-baseband-sim-zigbee",children:"Communication technologies \u2014 5G, narrow-band, baseband, SIM, Zigbee"}),"\n",(0,s.jsx)(n.p,{children:"Pick the right radio for the job. A wildlife sensor in a remote forest and a pallet tracker in a warehouse both need to move data, but the right answer is very different."}),"\n",(0,s.jsxs)(n.table,{children:[(0,s.jsx)(n.thead,{children:(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.th,{children:"Tech"}),(0,s.jsx)(n.th,{children:"What it is"}),(0,s.jsx)(n.th,{children:"Good for"}),(0,s.jsx)(n.th,{children:"Trade-offs"})]})}),(0,s.jsxs)(n.tbody,{children:[(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:(0,s.jsx)(n.strong,{children:"5G"})}),(0,s.jsx)(n.td,{children:"Latest cellular generation"}),(0,s.jsx)(n.td,{children:"Wide-area, high bandwidth, low latency"}),(0,s.jsx)(n.td,{children:"Expensive, overkill for simple sensors"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:(0,s.jsx)(n.strong,{children:"Narrow-band radio"})}),(0,s.jsx)(n.td,{children:"Low-data-rate radio on a narrow frequency band"}),(0,s.jsx)(n.td,{children:"Long range, low power (oilfield telemetry, remote sensors)"}),(0,s.jsx)(n.td,{children:"Tiny bandwidth"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:(0,s.jsx)(n.strong,{children:"Baseband radio"})}),(0,s.jsx)(n.td,{children:"Single-channel, unmodulated signal"}),(0,s.jsx)(n.td,{children:"Simple point-to-point"}),(0,s.jsx)(n.td,{children:"No multiplexing"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:(0,s.jsx)(n.strong,{children:"SIM card"})}),(0,s.jsx)(n.td,{children:"Subscriber identity module on a UICC"}),(0,s.jsx)(n.td,{children:"Identity + keys for cellular networks"}),(0,s.jsx)(n.td,{children:"Physical theft, SIM-swap attacks"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:(0,s.jsx)(n.strong,{children:"Zigbee"})}),(0,s.jsx)(n.td,{children:"IEEE 802.15.4 mesh for PANs"}),(0,s.jsx)(n.td,{children:"Home automation, medical telemetry, low-power mesh"}),(0,s.jsx)(n.td,{children:"Short range, small network"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:(0,s.jsx)(n.strong,{children:"Wi-Fi"})}),(0,s.jsx)(n.td,{children:"802.11 family"}),(0,s.jsx)(n.td,{children:"Ubiquitous, well supported"}),(0,s.jsx)(n.td,{children:"Power hungry"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:(0,s.jsx)(n.strong,{children:"Bluetooth / BLE"})}),(0,s.jsx)(n.td,{children:"Short-range PAN"}),(0,s.jsx)(n.td,{children:"Wearables, peripherals"}),(0,s.jsx)(n.td,{children:"Short range, pairing attacks"})]}),(0,s.jsxs)(n.tr,{children:[(0,s.jsx)(n.td,{children:(0,s.jsx)(n.strong,{children:"LoRa / LoRaWAN"})}),(0,s.jsx)(n.td,{children:"Long-range low-power WAN"}),(0,s.jsx)(n.td,{children:"City-wide sensor networks"}),(0,s.jsx)(n.td,{children:"Low data rate"})]})]})]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Baseband"})," deserves a second mention. In cellular devices, the baseband processor is a separate chip that runs a closed-source real-time stack talking to the cell network. Historically many basebands trust any message from the tower, which is why rogue base stations (IMSI catchers) work. Baseband also refers more generally to the original unmodulated signal that is encoded onto a carrier before transmission \u2014 a single channel of communication. Broadband, by contrast, bundles many channels together and requires equipment to separate them out again."]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"SIM cards"})," store the subscriber identity and the cryptographic keys the network uses to authenticate the device. Elements like provider identifier, serial numbers, and long-term keys live on a Universal Integrated Circuit Card (UICC). Attacks on SIMs include physical extraction and the now-notorious ",(0,s.jsx)(n.strong,{children:"SIM-swap"})," (tricking the carrier into porting a number to the attacker's SIM) \u2014 a particular risk because so many authentication flows still use SMS."]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Zigbee"})," is an IEEE 802.15.4 mesh protocol designed for small, low-power personal area networks \u2014 home automation, medical sensor telemetry, and low-bandwidth industrial data. It trades range and bandwidth for battery life measured in years. Security is defined in the standard but historically implemented poorly by cheap consumer gear; default keys and weak key distribution have been exploited."]}),"\n",(0,s.jsx)(n.h3,{id:"design-constraints--power-compute-patching-implied-trust",children:"Design constraints \u2014 power, compute, patching, implied trust"}),"\n",(0,s.jsx)(n.p,{children:"Every decision in embedded design pushes against constraints that do not exist in general-purpose computing:"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Power."})," Many IoT devices run on battery or harvested energy for years. Every joule spent on TLS, large crypto keys, or idle CPU is a joule not available for the device's actual purpose. Power also dictates radio choice: cellular needs a lot; Zigbee and LoRa need very little."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Compute."})," Tiny microcontrollers have kilobytes of RAM and megahertz of clock. AES-256 in constant time, certificate validation, or a full TLS handshake can be multiple seconds of stall. FPGAs, ASICs, and SoCs are the compute options; each trades performance, flexibility, and cost differently."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Network."})," Bandwidth is expensive (cellular data), scarce (Zigbee), or both. Protocols are stripped down; MQTT and CoAP replace HTTP. The value of a networked fleet grows roughly with the square of the node count, which is why vendors push everything onto the network whether it needs it or not."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Cryptography."})," Driven by the two above. The NIST Lightweight Cryptography project selected the Ascon family for standardisation to give embedded devices acceptable crypto at a fraction of the power cost. (Note: Ascon is not post-quantum safe.) Where full TLS is too heavy, designers reach for pre-shared keys, DTLS, or symmetric-only schemes \u2014 each with its own operational headaches."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Inability to patch."})," The ecosystem for most embedded devices lacks a patch culture \u2014 no OTA pipeline, no signing keys in use, no CI building firmware regularly. Many devices ship once and never update. A Raspberry Pi or Arduino has a clear update path; the embedded controller in a surveillance camera does not."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Authentication."})," Specialised devices often have no user at all, or one technician with a PIN. Full RBAC is overkill; a PIN plus physical security is the design target. That works until the device ends up on an internet-facing network and the implicit assumption of a trusted installer evaporates."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Range."})," Range is a function of power and frequency. Extending range costs power, and internet connectivity costs security. Every watt pushed into the radio is a watt not powering the sensor."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Cost."})," The value proposition is cost per deployed node. Extra features cost money; security is a feature that rarely shows up in the specification. Cost is simultaneously the reason the device exists and the reason the device is hard to secure."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Implied trust."})," The deepest issue. Specialised devices were not designed with adversarial networks in mind, so they trust anything they can talk to. Wrap them in proper segmentation or they will hand over keys to anyone on the wire."]}),"\n"]}),"\n",(0,s.jsxs)(n.p,{children:["Then there is the classic embedded footgun: ",(0,s.jsx)(n.strong,{children:"weak defaults"}),". Devices ship with a documented admin/admin credential and an expectation that the installer will change it. At scale, across hundreds of meters, cameras, or switches, a meaningful fraction never get changed. This is the single most common root cause in public IoT breaches. Regulators have begun to ban ship-with-admin-admin defaults for consumer IoT (UK PSTI Act, California SB-327); enterprise-grade devices often remain behind. Your procurement team should refuse to buy anything that does not force a unique credential on first boot."]}),"\n",(0,s.jsx)(n.h2,{id:"architecture-diagram",children:"Architecture diagram"}),"\n",(0,s.jsxs)(n.p,{children:["A reference segmentation for an enterprise running both IT and OT / IoT at ",(0,s.jsx)(n.code,{children:"example.local"}),". The point of the picture is the dual DMZ separating business IT from the control network, plus dedicated VLANs for IoT devices that should never sit next to general user traffic. Read it top to bottom: the further you travel from the internet, the smaller the number of people and devices that should be able to reach a given box, and the stricter the authentication, logging, and change control."]}),"\n",(0,s.jsx)(n.mermaid,{value:'flowchart TB\n    subgraph IT["Enterprise IT (Levels 4-5)"]\n        USER[User laptops<br/>EXAMPLE\\\\users]\n        SRV[App / file servers]\n        AD[Active Directory<br/>example.local]\n        SIEM[SIEM / EDR]\n    end\n\n    subgraph IOT["IoT VLAN"]\n        CAM[IP cameras]\n        MFP[Multifunction printers]\n        HVACIOT[Smart thermostats]\n        BADGE[Badge readers]\n    end\n\n    subgraph DMZ["Industrial DMZ (Level 3.5)"]\n        HIST[Historian replica]\n        JUMP[Jump host +<br/>vendor remote access]\n        PATCH[Patch / AV staging]\n    end\n\n    subgraph OT["OT / SCADA (Levels 0-3)"]\n        HMI[HMI workstation]\n        SCADASRV[SCADA server]\n        PLC[PLC / RTU]\n        SENSOR[Sensors + actuators]\n    end\n\n    INET[Internet]\n\n    INET --\x3e FW1[Perimeter firewall]\n    FW1 --\x3e IT\n    IT --\x3e|strict allow-list| FW2[OT boundary firewall]\n    FW2 --\x3e DMZ\n    DMZ --\x3e|one-way or<br/>strictly filtered| FW3[Cell / zone firewall]\n    FW3 --\x3e OT\n    HMI --\x3e SCADASRV --\x3e PLC --\x3e SENSOR\n    HIST -.replicates from.-> SCADASRV\n    IT --- IOT\n    SIEM -.collects from.-> IOT\n    SIEM -.collects from.-> DMZ'}),"\n",(0,s.jsx)(n.p,{children:"The rules of engagement: nothing in IT talks directly to a PLC; everything goes through the industrial DMZ. The historian lives in the DMZ and replicates from the OT side. Vendor remote access terminates at a jump host with MFA and session recording. The IoT VLAN is firewalled off from general user subnets and only allowed to reach its cloud endpoints and the SIEM collector."}),"\n",(0,s.jsxs)(n.p,{children:["A second pattern worth naming is the ",(0,s.jsx)(n.strong,{children:"unidirectional gateway"})," or ",(0,s.jsx)(n.strong,{children:"data diode"})," \u2014 a hardware component that physically allows traffic in one direction only (typically from OT to IT, so the historian replica can be populated without opening a return path). In environments where the business impact of an OT compromise is high \u2014 power generation, chemical plants, safety-instrumented systems \u2014 diodes are worth the cost. For many enterprises a strict firewall with deny-by-default rules and logging is sufficient."]}),"\n",(0,s.jsx)(n.p,{children:"The IoT VLAN in the diagram is deliberately separated from the OT/SCADA side. IoT devices (cameras, badge readers, MFPs) are built for consumer-grade networks and should not be allowed near industrial control surfaces. A single flat network hosting both is the most common real-world mistake."}),"\n",(0,s.jsx)(n.h2,{id:"hands-on--practice",children:"Hands-on / practice"}),"\n",(0,s.jsx)(n.p,{children:"Five exercises a learner can run against a lab network or a willing piece of production infrastructure. The goal is to see, with your own eyes, what an embedded or OT device exposes to the network around it. Most of these take under an hour and use tools you already have on a security workstation."}),"\n",(0,s.jsx)(n.h3,{id:"1-fingerprint-an-iot-device-on-the-network",children:"1. Fingerprint an IoT device on the network"}),"\n",(0,s.jsx)(n.p,{children:"Pick an IP camera, printer, or smart plug on a lab VLAN. From a Linux or WSL box:"}),"\n",(0,s.jsx)(n.pre,{children:(0,s.jsx)(n.code,{className:"language-bash",children:"# Find it on the segment\nnmap -sn 192.0.2.0/24\n\n# Full service + OS fingerprint\nnmap -sV -O -p- 192.0.2.50 -oN iot-fingerprint.txt\n\n# Banner grab the web UI\ncurl -sI http://192.0.2.50/\ncurl -s http://192.0.2.50/ | head -50\n\n# SNMP sysDescr (often leaks full model + firmware)\nsnmpwalk -v2c -c public 192.0.2.50 sysDescr sysName\n"})}),"\n",(0,s.jsxs)(n.p,{children:["Look for: firmware version in banners, default web paths (",(0,s.jsx)(n.code,{children:"/cgi-bin/"}),", ",(0,s.jsx)(n.code,{children:"/admin/"}),", ",(0,s.jsx)(n.code,{children:"/setup.cgi"}),"), HTTP basic auth realms that leak the model name, exposed Telnet (port 23), exposed RTSP (port 554), and SNMP on 161. Write down what the device told you without authenticating \u2014 that is what an attacker on the same VLAN sees. If the device responds to SNMP with community string ",(0,s.jsx)(n.code,{children:"public"}),", that is a finding in its own right."]}),"\n",(0,s.jsx)(n.h3,{id:"2-check-default-credentials-against-a-vendor-list",children:"2. Check default credentials against a vendor list"}),"\n",(0,s.jsx)(n.p,{children:"Weak defaults are the most common root cause of public IoT breaches, so this is not a theoretical exercise. Using the fingerprint from exercise 1, look up the make and model on the vendor's support page and on public default-credentials lists (for example, the Mirai source code has a table; the CIRT default password DB is another). Then confirm the credentials have been changed:"}),"\n",(0,s.jsx)(n.pre,{children:(0,s.jsx)(n.code,{className:"language-bash",children:"# If Telnet is open (it should not be)\ntelnet 192.0.2.50\n\n# HTTP basic auth probe (do not brute-force, just try the documented default)\ncurl -u admin:admin -sI http://192.0.2.50/\n\n# For an MFP, probe the management port\ncurl -sI http://192.0.2.60:9100/\n\n# SNMPv2 with the default community\nsnmpwalk -v2c -c public 192.0.2.50 system\n"})}),"\n",(0,s.jsxs)(n.p,{children:["Log whatever logs in. Any device on the inventory whose documented default still works is a P1 finding \u2014 rotate the credential immediately, and escalate if the device is on a segment that can reach user or server subnets. Keep the test ",(0,s.jsx)(n.strong,{children:"narrow and documented"})," \u2014 a single authentication attempt with the documented default is a legitimate assessment; a brute-force run against production gear is not."]}),"\n",(0,s.jsx)(n.h3,{id:"3-ot--it-segmentation-review",children:"3. OT / IT segmentation review"}),"\n",(0,s.jsx)(n.p,{children:'Segmentation is the single most important control between IT and OT. It is also the one most often misconfigured or silently regressed over time as someone adds "just one more rule" to get a dashboard working. The goal of this exercise is to confirm that from an ordinary user workstation you cannot reach OT assets directly.'}),"\n",(0,s.jsxs)(n.p,{children:["Pick the cell or IoT VLAN from your network diagram. Confirm that a host on a user VLAN ",(0,s.jsx)(n.strong,{children:"cannot"})," open arbitrary ports into it. From a test laptop in the user subnet:"]}),"\n",(0,s.jsx)(n.pre,{children:(0,s.jsx)(n.code,{className:"language-bash",children:"# Connectivity probe on a known OT port (Modbus TCP = 502, Ethernet/IP = 44818)\nnc -vz 10.30.0.15 502\nnc -vz 10.30.0.15 44818\n\n# Scan the whole OT subnet for reachable TCP services\nnmap -Pn -sT --top-ports 1000 10.30.0.0/24\n"})}),"\n",(0,s.jsxs)(n.p,{children:["Anything that comes back ",(0,s.jsx)(n.strong,{children:"should"})," be a deliberate allow-list entry in the OT boundary firewall (for example, historian replication on port 1433 to the DMZ). If you can reach a PLC directly on port 502 from a user VLAN, segmentation is broken and the remediation is a firewall rule, not a wish. File a P1 finding and rope in whoever owns the network \u2014 this is a breach waiting to happen."]}),"\n",(0,s.jsx)(n.p,{children:'Repeat the test quarterly. Rules drift; engineers "temporarily" open something for a vendor call and forget to revert. Regular, deliberate, documented checks catch that before an adversary does.'}),"\n",(0,s.jsx)(n.h3,{id:"4-firmware-version-audit",children:"4. Firmware version audit"}),"\n",(0,s.jsx)(n.p,{children:"Firmware is the embedded-world equivalent of a software patch. For every IoT / OT asset, you want to know: what version is deployed, what version the vendor released last, and whether any of the releases between those two fixed security issues."}),"\n",(0,s.jsx)(n.p,{children:"Export a CSV from your CMDB or the vendor's management tool with every IoT / OT device, its model, and its current firmware. Then for each vendor, pull the latest released firmware from the public support page and diff:"}),"\n",(0,s.jsx)(n.pre,{children:(0,s.jsx)(n.code,{className:"language-powershell",children:"# PowerShell \u2014 compare installed vs latest for a printer fleet\nImport-Csv .\\mfp-inventory.csv |\n    ForEach-Object {\n        [pscustomobject]@{\n            Host    = $_.Host\n            Model   = $_.Model\n            Current = $_.FirmwareVersion\n            Latest  = (Get-VendorLatest -Model $_.Model)\n        }\n    } |\n    Where-Object { $_.Current -ne $_.Latest } |\n    Sort-Object Model |\n    Export-Csv .\\mfp-firmware-delta.csv -NoTypeInformation\n"})}),"\n",(0,s.jsx)(n.p,{children:"Anything behind more than one release \u2014 or behind a release marked security-relevant in the vendor changelog \u2014 is a remediation candidate. Log the exposure, open a ticket against the asset owner, and set a deadline consistent with your SLA matrix. If a vendor has stopped shipping firmware for a given model, the device is end-of-life from a security perspective; feed that into the replacement plan rather than letting it ride forever."}),"\n",(0,s.jsx)(n.h3,{id:"5-baseline-network-traffic-from-an-iot-device",children:"5. Baseline network traffic from an IoT device"}),"\n",(0,s.jsx)(n.p,{children:"Most IoT devices have a small, predictable set of outbound destinations. Point a capture at one for an hour and see:"}),"\n",(0,s.jsx)(n.pre,{children:(0,s.jsx)(n.code,{className:"language-bash",children:'# Capture all traffic to/from the device\nsudo tcpdump -i eth0 -w iot-capture.pcap host 192.0.2.50\n\n# Summarise destinations afterwards\ntshark -r iot-capture.pcap -qz conv,ip\ntshark -r iot-capture.pcap -qz hosts\n\n# Decode application protocols (MQTT, HTTP, TLS SNI)\ntshark -r iot-capture.pcap -Y "mqtt || http.request"\ntshark -r iot-capture.pcap -Y "tls.handshake.extensions_server_name" \\\n  -T fields -e tls.handshake.extensions_server_name | sort -u\n'})}),"\n",(0,s.jsx)(n.p,{children:"Expected: a DNS query or two, NTP, and a connection to the vendor's cloud on port 443. Unexpected: connections to IPs outside the vendor's ASN, cleartext HTTP on port 80, SMB scans, or anything resembling command-and-control beaconing. Treat anything unexpected as an incident and pull the device off the network while you investigate. Save the capture as a known-good baseline \u2014 future anomalies will be easier to spot against a reference."}),"\n",(0,s.jsx)(n.h2,{id:"worked-example",children:"Worked example"}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.code,{children:"example.local"})," is a 1,500-employee manufacturing company with three sites. Facilities management wants to roll out a new ",(0,s.jsx)(n.strong,{children:"SCADA-based HVAC controller"})," across all three buildings \u2014 the ageing analog BMS is being replaced with a modern Modbus/TCP + OPC UA stack from a named vendor, with remote monitoring from the head office. The vendor proposal includes an internet-connected cloud dashboard, a 24/7 remote support tunnel, and direct connection of the new PLCs to the existing corporate network."]}),"\n",(0,s.jsx)(n.p,{children:'Security does not push back by saying "no". Security pushes back by redesigning the deployment so the business value is preserved and the risk is bounded. Here is how the security program threads into each phase.'}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"Phase 1 \u2014 pre-deployment threat model."})}),"\n",(0,s.jsx)(n.p,{children:"The sec eng and facilities lead sit down with the integrator two months before the first sensor is installed. They enumerate:"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:"Assets: 12 PLCs (one per floor per site), 4 HMI workstations, 1 SCADA server per site, 1 central historian at HQ, 350 sensors and 80 actuators across the three buildings."}),"\n",(0,s.jsx)(n.li,{children:"Trust boundaries: between sensor network and PLC, between PLC and HMI, between HMI and historian, between site and HQ, between HQ SCADA and the corporate IT network."}),"\n",(0,s.jsx)(n.li,{children:"Threats: ransomware on the HMI workstations (Windows 10 LTSC); unauthorised commands on Modbus/TCP (no authentication in the protocol); vendor remote access abuse; weak defaults on the PLCs; lateral movement from the IoT VLAN (where smart thermostats live) into OT."}),"\n",(0,s.jsx)(n.li,{children:"Crown jewels: continuous operation during working hours; safety interlocks on boiler controls."}),"\n"]}),"\n",(0,s.jsx)(n.p,{children:"Output: a one-page threat model with a prioritised risk register. The integrator's contract is rewritten to require: signed firmware only, no plaintext protocols across site boundaries, no hard-coded credentials, a 72-hour patch SLA for critical CVEs affecting installed components."}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"Phase 2 \u2014 network design."})}),"\n",(0,s.jsx)(n.p,{children:"Built to the Purdue model. The key decision is that existing corporate IT and the new SCADA stack do not share a broadcast domain at any layer \u2014 every crossing is mediated by a firewall, and every firewall has deny-by-default with named allow rules."}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"OT VLAN (10.30.0.0/24)"})," \u2014 PLCs, sensors, actuators. No internet. No IT traffic."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"HMI VLAN (10.31.0.0/24)"})," \u2014 HMI workstations and SCADA servers. Talks to OT VLAN on a strict allow-list (Modbus, OPC UA)."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Industrial DMZ (10.32.0.0/24)"})," \u2014 historian replica, patch staging, vendor jump host with MFA and session recording. Talks to HMI VLAN on a strict allow-list (OPC UA tunnel to historian, RDP from jump host to HMI)."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"IT core"})," \u2014 AD (",(0,s.jsx)(n.code,{children:"example.local"}),"), SIEM, endpoint management. Talks to DMZ on strict allow-list (SIEM collection, patch sync)."]}),"\n"]}),"\n",(0,s.jsx)(n.p,{children:"The OT boundary firewall is deny-by-default both ways. Every flow has a justification documented in a change ticket."}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"Phase 3 \u2014 hardening the endpoints."})}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"PLCs."})," Default passwords rotated before the PLC is ever connected to a network. Programming port (physical) normally disabled via a keyswitch left in the RUN position, with the key held by the OT lead. Firmware updated to the vendor's current release before commissioning."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"HMI workstations."})," Windows 10 LTSC, application whitelisting via WDAC, local admin rotated via LAPS as ",(0,s.jsx)(n.code,{children:"EXAMPLE\\hmi-admin"}),", domain joined to a dedicated OU with strict GPO. No email, no web browsing \u2014 the HMI is not a general workstation. USB ports disabled in firmware or via GPO except for specifically whitelisted maintenance sticks."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"SCADA servers."})," Hardened per CIS benchmark, minimal services, scanner agent reporting to the corporate vulnerability management platform, logs forwarded to SIEM. A second SCADA server per site in warm standby on separate physical hardware."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Historian."})," The replica in the DMZ receives one-way from the OT side (dataflow diode where budget allows, strict firewall + unidirectional gateway otherwise). The DMZ copy is the one that IT analytics query. No IT user ever has a credential that can reach the source historian directly."]}),"\n"]}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"Phase 3b \u2014 credential and key management."})}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:"Every device credential rotated off the factory default before connection. Credentials stored in the corporate password vault with audit logging."}),"\n",(0,s.jsxs)(n.li,{children:["A single service account ",(0,s.jsx)(n.code,{children:"EXAMPLE\\svc_scada_scan"})," is used by the corporate vulnerability scanner to inventory HMI and SCADA server assets; it has read-only rights and is rotated monthly."]}),"\n",(0,s.jsx)(n.li,{children:"Engineers who need access to the jump host enrol a FIDO2 security key in addition to their normal MFA factor. The extra factor is specifically for OT-impacting tasks."}),"\n",(0,s.jsx)(n.li,{children:"No shared accounts on HMIs. Each operator has a named login tied to Active Directory."}),"\n"]}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"Phase 4 \u2014 monitoring."})}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:"SIEM collects from the HMI VLAN, the DMZ, and the IT side. PLCs are too dumb to log; instead a passive network tap in the OT VLAN feeds an OT-aware IDS (tools like Nozomi, Dragos, or Claroty) that understands Modbus and OPC UA and can flag unexpected function codes, new PLC firmware pushes, or unauthorised write commands."}),"\n",(0,s.jsx)(n.li,{children:"Baseline established over the first two weeks of normal operation. Alerts tuned on anomalies: an HMI talking to a PLC it never talked to before, a write command outside business hours, a new MAC address on the OT VLAN."}),"\n",(0,s.jsx)(n.li,{children:"Every vendor remote-support session goes through the jump host with MFA and session recording. Recordings retained for 12 months."}),"\n",(0,s.jsx)(n.li,{children:'A physical "break-glass" procedure is documented for the case where the SCADA stack is unavailable \u2014 manual valve operation, paper logging, and a clearly named incident commander. The security controls must not prevent the plant from falling back to analog operation in a crisis.'}),"\n"]}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"Phase 5 \u2014 ongoing maintenance."})}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:"Firmware updates to PLCs and sensors happen during scheduled quarterly maintenance windows, coordinated with facilities. The vendor's patch notes are reviewed by a qualified engineer; updates are staged on a twin in the lab first."}),"\n",(0,s.jsx)(n.li,{children:"HMI Windows patching piggybacks on the corporate patch cycle but with a one-week lag behind the main server fleet, so any broken patch is caught in IT before it hits OT."}),"\n",(0,s.jsx)(n.li,{children:'Annual red-team exercise includes the OT boundary; the explicit rules of engagement say "detect and segment, do not compromise production".'}),"\n",(0,s.jsx)(n.li,{children:"Risk-acceptance register reviewed quarterly; any PLC that cannot be patched carries a documented compensating control (additional segmentation, tighter monitoring, physical key lock)."}),"\n",(0,s.jsx)(n.li,{children:"Sensor and actuator inventory reconciled with the CMDB twice a year; any device that appears on the OT VLAN without a CMDB record is treated as a finding."}),"\n"]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Outcome."})," The facilities upgrade delivers real-time energy dashboards, remote issue triage, and centralised reporting \u2014 without making the boiler controller reachable from a phishing link. The cost is the boundary firewall, the jump host, an OT-aware IDS licence, and about two extra weeks of integrator time. That is a cheap way to avoid being the next HVAC-vendor breach case study."]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"What security was not asked to do."})," Equally important: the program did not try to put an EDR agent on a PLC, did not demand Windows Update on an HMI that the vendor will only support at a specific patch level, and did not require the integrator to hand over firmware source. Pushing controls that the devices cannot host is how security loses credibility with engineering. The right answer is segment, monitor, control who can reach the box, and make sure the box you buy is one whose vendor treats security seriously."]}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"How the deployment is measured."})," A handful of numbers reported to the CISO quarterly: number of flows allowed across the OT boundary firewall (target: stable or shrinking), count of vendor remote sessions (logged with purpose), mean time to detect anomalous OT traffic, patch SLA compliance for HMI workstations, and firmware-version delta against latest vendor release for PLCs. Each number is an indicator; together they tell a story about whether the program is eroding or holding."]}),"\n",(0,s.jsx)(n.h2,{id:"troubleshooting-and-pitfalls",children:"Troubleshooting and pitfalls"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:'Treating IoT devices as "just another computer".'})," They are not. They lack agent support, patch cadence, and user accounts. Force-fitting endpoint management onto a camera breaks the camera. Build IoT controls around network segmentation and monitoring, not host agents."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Buying without a lifecycle conversation."})," Facilities bought the new BMS on a capex cycle; IT got handed the firewall requirement three months later. Involve security at procurement, not at go-live."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Leaving default credentials on anything deployed at scale."})," If you deploy 200 cameras and rotate the password on 190, the remaining 10 are your breach story. Use installation checklists with a mandatory credential-rotation step and verify via a scanner sweep."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Flat networks in the plant."}),' "We have a firewall at the perimeter" means nothing if the HMI and the corporate laptop are on the same VLAN. East-west traffic on a flat plant network is how ransomware gets from an email attachment to the PLCs.']}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Vendor remote access straight into OT."})," The integrator's laptop with a static VPN into the control network is a textbook ransomware entry point. Terminate remote access at a jump host with MFA and session recording."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Patching SCADA like IT."})," You cannot apply a Patch Tuesday reboot to a running PLC. OT patching needs planned windows, vendor validation, and tested rollback. Stage patches in the DMZ, test on a twin, deploy in maintenance windows."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Forgetting that specialised systems are life-safety systems."})," Medical devices, vehicles, aircraft, and certain industrial controls can kill people if they misbehave. Security on these devices is safety engineering \u2014 document, review, and do not ship a change without a formal risk analysis."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Assuming air-gap is still intact."}),' Every "air-gapped" network turns out to have a USB stick, a maintenance laptop, or a rogue cellular modem. Audit periodically by looking at DNS queries from the supposedly isolated segment.']}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Believing the radio layer is safe because it is weird."})," Zigbee, baseband, proprietary 433 MHz \u2014 all have been broken publicly. A researcher with an SDR and a weekend can often replay or inject; a motivated adversary with a few thousand dollars of kit absolutely can."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Forgetting the supply chain."})," The firmware on that camera was built on a Linux image from a chip vendor, with libraries from an SoC vendor, delivered by an integrator, installed by a subcontractor. Any one of them can ship you a backdoor; your only defence is segmentation and monitoring."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"No lifecycle plan."})," Devices bought in 2020 will still be on your network in 2035. Plan the decommission date at purchase; do not discover it when the vendor stops shipping firmware."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Ignoring the safety case."}),' In OT, the first question should always be "does this control change the physics of the process?" A security misconfiguration that could cause a boiler to over-pressurise is an engineering problem, not an IT problem. Loop safety engineering into the change-control flow.']}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"No logging of vendor remote sessions."}),' Your integrator pays one contractor to patch a PLC, that contractor\'s laptop carries ransomware, your weekend is ruined \u2014 and you have no recording of what was done, because the jump host had session recording disabled "for performance". Always record, always keep the recording, always review periodically.']}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Scanner sweeps against fragile OT devices."})," Even a polite port scan has crashed PLCs, HMIs, and sensors over the years. Use passive discovery (span port feeding an OT-aware tool) for the OT VLAN rather than active nmap. Reserve active scanning for IT and the DMZ."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Assuming one standard fits all."})," Modbus, OPC UA, DNP3, BACnet, EtherNet/IP, PROFINET \u2014 industrial protocols are a zoo. Each has its own security (or lack of). A rule that makes sense for Modbus is wrong for OPC UA. Invest in an OT-aware IDS that speaks the protocols you actually run."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:'Confusing "we segmented it" with "we segmented it properly".'}),' A VLAN alone is not segmentation; the router or firewall between the VLANs is. If the "OT VLAN" shares an L3 gateway with user traffic and has no ACL, it is not segmented.']}),"\n"]}),"\n",(0,s.jsx)(n.h2,{id:"key-takeaways",children:"Key takeaways"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:"Embedded systems are purpose-built computers inside everything from printers to pacemakers. They optimise for cost and longevity, not security."}),"\n",(0,s.jsx)(n.li,{children:"IoT is the networked variant; OT / ICS / SCADA is the industrial variant. They overlap but the engineering cultures differ."}),"\n",(0,s.jsx)(n.li,{children:"Treat development boards \u2014 Raspberry Pi, Arduino, FPGA \u2014 as real assets when they enter production; especially a Pi, which is a full Linux host."}),"\n",(0,s.jsx)(n.li,{children:"SCADA networks should be segmented per the Purdue model: field devices and controllers inside, DMZ for crossovers, IT outside."}),"\n",(0,s.jsx)(n.li,{children:"Specialised systems (medical, vehicle, aircraft, smart meters) bring safety consequences \u2014 security there is safety engineering."}),"\n",(0,s.jsx)(n.li,{children:"The communication layer matters: 5G, Zigbee, narrow-band, baseband, and SIM each have their own failure modes and appropriate uses."}),"\n",(0,s.jsx)(n.li,{children:"The defining design constraints are power, compute, patchability, authentication, range, cost, and implied trust. Every security decision trades against these."}),"\n",(0,s.jsx)(n.li,{children:"Weak defaults plus inability to patch equals permanent exposure. Mitigate with segmentation, monitoring, and compensating controls when patching is off the table."}),"\n",(0,s.jsx)(n.li,{children:"Vendor remote access and flat OT networks are the two most common real-world breach paths. Fix both before you fix anything else."}),"\n",(0,s.jsx)(n.li,{children:"Security for embedded and OT is mostly about containment. You cannot patch everything; you can control who talks to what, watch for surprises, and keep a manual fallback."}),"\n",(0,s.jsx)(n.li,{children:"Procurement is where embedded security is won or lost. Push security requirements into the contract before money changes hands."}),"\n"]}),"\n",(0,s.jsx)(n.h2,{id:"references",children:"References"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:"CompTIA Security+ SY0-701 \u2014 embedded and specialized system objectives"}),"\n",(0,s.jsxs)(n.li,{children:["NIST SP 800-82 Rev. 3 \u2014 ",(0,s.jsx)(n.em,{children:"Guide to Operational Technology (OT) Security"})," \u2014 ",(0,s.jsx)(n.a,{href:"https://csrc.nist.gov/publications/detail/sp/800-82/rev-3/final",target:"_blank",rel:"noopener noreferrer",children:"https://csrc.nist.gov/publications/detail/sp/800-82/rev-3/final"})]}),"\n",(0,s.jsxs)(n.li,{children:["NIST SP 800-213 \u2014 ",(0,s.jsx)(n.em,{children:"IoT Device Cybersecurity Guidance for the Federal Government"})," \u2014 ",(0,s.jsx)(n.a,{href:"https://csrc.nist.gov/publications/detail/sp/800-213/final",target:"_blank",rel:"noopener noreferrer",children:"https://csrc.nist.gov/publications/detail/sp/800-213/final"})]}),"\n",(0,s.jsxs)(n.li,{children:["NIST SP 800-213A \u2014 ",(0,s.jsx)(n.em,{children:"IoT Device Cybersecurity Requirements Catalog"})," \u2014 ",(0,s.jsx)(n.a,{href:"https://csrc.nist.gov/publications/detail/sp/800-213a/final",target:"_blank",rel:"noopener noreferrer",children:"https://csrc.nist.gov/publications/detail/sp/800-213a/final"})]}),"\n",(0,s.jsxs)(n.li,{children:["NISTIR 8259 series \u2014 ",(0,s.jsx)(n.em,{children:"Foundational Cybersecurity Activities for IoT Device Manufacturers"})," \u2014 ",(0,s.jsx)(n.a,{href:"https://csrc.nist.gov/publications/detail/nistir/8259/final",target:"_blank",rel:"noopener noreferrer",children:"https://csrc.nist.gov/publications/detail/nistir/8259/final"})]}),"\n",(0,s.jsxs)(n.li,{children:["NIST Lightweight Cryptography Project (Ascon) \u2014 ",(0,s.jsx)(n.a,{href:"https://csrc.nist.gov/Projects/lightweight-cryptography",target:"_blank",rel:"noopener noreferrer",children:"https://csrc.nist.gov/Projects/lightweight-cryptography"})]}),"\n",(0,s.jsxs)(n.li,{children:["ISA/IEC 62443 \u2014 ",(0,s.jsx)(n.em,{children:"Security for Industrial Automation and Control Systems"})," \u2014 ",(0,s.jsx)(n.a,{href:"https://www.isa.org/standards-and-publications/isa-standards/isa-iec-62443-series-of-standards",target:"_blank",rel:"noopener noreferrer",children:"https://www.isa.org/standards-and-publications/isa-standards/isa-iec-62443-series-of-standards"})]}),"\n",(0,s.jsxs)(n.li,{children:["Purdue Enterprise Reference Architecture \u2014 ",(0,s.jsx)(n.a,{href:"https://www.isa.org/",target:"_blank",rel:"noopener noreferrer",children:"https://www.isa.org/"})]}),"\n",(0,s.jsxs)(n.li,{children:["CISA ICS Advisories \u2014 ",(0,s.jsx)(n.a,{href:"https://www.cisa.gov/news-events/cybersecurity-advisories/ics-advisories",target:"_blank",rel:"noopener noreferrer",children:"https://www.cisa.gov/news-events/cybersecurity-advisories/ics-advisories"})]}),"\n",(0,s.jsxs)(n.li,{children:["CISA \u2014 ",(0,s.jsx)(n.em,{children:"Recommended Practice for Securing Control Systems"})," \u2014 ",(0,s.jsx)(n.a,{href:"https://www.cisa.gov/uscert/ics/Recommended-Practices",target:"_blank",rel:"noopener noreferrer",children:"https://www.cisa.gov/uscert/ics/Recommended-Practices"})]}),"\n",(0,s.jsxs)(n.li,{children:["OWASP IoT Top 10 \u2014 ",(0,s.jsx)(n.a,{href:"https://owasp.org/www-project-internet-of-things-top-10/",target:"_blank",rel:"noopener noreferrer",children:"https://owasp.org/www-project-internet-of-things-top-10/"})]}),"\n",(0,s.jsxs)(n.li,{children:["OWASP Embedded Application Security Project \u2014 ",(0,s.jsx)(n.a,{href:"https://owasp.org/www-project-embedded-application-security/",target:"_blank",rel:"noopener noreferrer",children:"https://owasp.org/www-project-embedded-application-security/"})]}),"\n",(0,s.jsxs)(n.li,{children:["FDA Cybersecurity in Medical Devices \u2014 ",(0,s.jsx)(n.a,{href:"https://www.fda.gov/medical-devices/digital-health-center-excellence/cybersecurity",target:"_blank",rel:"noopener noreferrer",children:"https://www.fda.gov/medical-devices/digital-health-center-excellence/cybersecurity"})]}),"\n",(0,s.jsxs)(n.li,{children:["Auto-ISAC \u2014 ",(0,s.jsx)(n.a,{href:"https://automotiveisac.com/",target:"_blank",rel:"noopener noreferrer",children:"https://automotiveisac.com/"})]}),"\n",(0,s.jsxs)(n.li,{children:["Zigbee Alliance / Connectivity Standards Alliance \u2014 ",(0,s.jsx)(n.a,{href:"https://csa-iot.org/",target:"_blank",rel:"noopener noreferrer",children:"https://csa-iot.org/"})]}),"\n",(0,s.jsxs)(n.li,{children:["3GPP 5G Security specifications (TS 33.501) \u2014 ",(0,s.jsx)(n.a,{href:"https://www.3gpp.org/",target:"_blank",rel:"noopener noreferrer",children:"https://www.3gpp.org/"})]}),"\n"]})]})}function h(e={}){const{wrapper:n}={...(0,i.R)(),...e.components};return n?(0,s.jsx)(n,{...e,children:(0,s.jsx)(c,{...e})}):c(e)}},28453(e,n,t){t.d(n,{R:()=>a,x:()=>o});var r=t(96540);const s={},i=r.createContext(s);function a(e){const n=r.useContext(i);return r.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function o(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:a(e.components),r.createElement(i.Provider,{value:n},e.children)}}}]);